const agora = new Date();
const horaBR = parseInt(agora.toLocaleString('pt-BR', {timeZone: 'America/Sao_Paulo', hour: '2-digit', hour12: false}));
const dataBR = agora.toLocaleDateString('pt-BR', {timeZone: 'America/Sao_Paulo'});
let periodo;
if (horaBR >= 5 && horaBR < 12) periodo = 'MANHA';
else if (horaBR >= 12 && horaBR < 18) periodo = 'TARDE';
else periodo = 'NOITE';
const saudacoes = {MANHA: 'Bom dia, Diretor.', TARDE: 'Boa tarde, Diretor.', NOITE: 'Boa noite, Diretor.'};
let statusProjetos = '';
try {
  const wipRaw = $('Ler WIP_BOARD').item.json;
  let wip;
  if (wipRaw && wipRaw.board) {
    wip = wipRaw;
  } else if (wipRaw && wipRaw.content) {
    const decoded = Buffer.from(wipRaw.content.replace(/\n/g, ''), 'base64').toString('utf8');
    wip = JSON.parse(decoded.replace(/^\uFEFF/, ''));
  } else if (wipRaw && typeof wipRaw.body === 'string') {
    wip = JSON.parse(wipRaw.body.replace(/^\uFEFF/, ''));
  } else {
    wip = {};
  }
  const board = wip.board || {};
  const todos = [];
  if (board.build) todos.push(...board.build);
  if (board.check) todos.push(...board.check);
  if (board.retainer) todos.push(...board.retainer);
  if (board.entregue) todos.push(...board.entregue);
  const linhas = todos.map(function(p) {
    const nome = p.cliente || p.id || 'Projeto';
    const st = (p.status || 'ATIVO').split(' -- ')[0];
    return '- ' + nome + ': ' + st;
  });
  statusProjetos = linhas.length > 0 ? linhas.join('\n') : '- (sem projetos ativos)';
} catch (e) {
  statusProjetos = '- (ERRO: ' + e.message + ')';
}
return [{json: {periodo: periodo, saudacao: saudacoes[periodo], hora: horaBR, data: dataBR, timestamp: agora.toISOString(), statusProjetos: statusProjetos}}];
